{"code":"import json, re
# load data from previous tool outputs
pubs = var_call_JgQzUMa7emZPxYCJcOJfVL1O
# var_call_JgQz... contains a dict with 'pubnums'
uc_pubnums = set(pubs.get('pubnums', []))

# load citing records
path = var_call_60MWxJZ1Kxcfs8YNkgKEk5Vf
with open(path, 'r', encoding='utf-8') as f:
    citing_records = json.load(f)

# helper to parse citation field which is JSON-like string

def parse_json_field(s):
    if not s:
        return []
    try:
        return json.loads(s)
    except Exception:
        # try to fix single quotes
        try:
            return json.loads(s.replace("'", '"'))
        except Exception:
            return []


def extract_assignee(pi):
    if not pi:
        return ''
    pi = pi.strip()
    # try patterns
    patterns = [r'^(.*?)\s+(?:holds|holds the|owns|is owned by|owned by|is assigned to|assigned to|is the|has)\b',
                r'\bowned by\s+(.*?)(?:\s|,|\.|$)',
                r'\bassigned to\s+(.*?)(?:\s|,|\.|$)',
                r'^(.*?)\s+holds the',
               ]
    for pat in patterns:
        m = re.search(pat, pi, flags=re.IGNORECASE)
        if m:
            g = m.group(1).strip()
            # cleanup trailing phrases
            g = re.sub(r"\s+the$", '', g)
            return g.upper()
    # fallback: take leading token up to 'holds' or 'has'
    m = re.match(r'^(\S+(?:\s+\S+){0,6})', pi)
    if m:
        return m.group(1).upper()
    return pi.upper()

assignee_to_codes = {}
code_to_assignees = {}

for rec in citing_records:
    pi = rec.get('Patents_info','')
    assignee = extract_assignee(pi)
    if not assignee:
        continue
    # skip if assignee is UNIV CALIFORNIA
    if 'UNIV CALIFORNIA' in assignee:
        continue
    # parse citation list
    citations = parse_json_field(rec.get('citation',''))
    cited_pubnums = set()
    for c in citations:
        pn = c.get('publication_number','')
        if pn:
            pn = pn.strip()
            if pn in uc_pubnums:
                cited_pubnums.add(pn)
    if not cited_pubnums:
        continue
    # parse cpc primary code
    cpc_list = parse_json_field(rec.get('cpc',''))
    primary_codes = [entry.get('code') for entry in cpc_list if entry.get('first')]
    # if none marked first, take first code if exists
    if not primary_codes and cpc_list:
        primary_codes = [cpc_list[0].get('code')]
    # normalize codes and keep unique
    primary_codes = [pc for pc in primary_codes if pc]
    if not primary_codes:
        continue
    # store unique codes per assignee
    assignee_to_codes.setdefault(assignee, set()).update(primary_codes)
    for pc in primary_codes:
        code_to_assignees.setdefault(pc, set()).add(assignee)

# convert sets to lists
assignee_to_codes_list = {a: sorted(list(codes)) for a,codes in assignee_to_codes.items()}
codes_list = sorted(list(code_to_assignees.keys()))

result = {'assignee_to_codes': assignee_to_codes_list, 'codes': codes_list}
print('__RESULT__:')
print(json.dumps(result))"}
